solutions.python:
import sys
from typing import List

class Solution:
    def validateExposedPorts(self, ports: List[str]) -> bool:
        # Check if each port is within the valid range
        for port in ports:
            parts = port.split(' ')
            if int(parts[1]) < 1 or int(parts[1]) > 65535:
                return False
        # Check for port collisions
        set = set()
        for port in ports:
            parts = port.split(' ')
            set.add(int(parts[1]))
        return len(set) == len(ports)

if __name__ == '__main__':
    inp = sys.stdin.readlines()
    inp = inp[0].strip().split(' ')  # Remove empty lines
    print(Solution().validateExposedPorts(inp).toString())
